import React, { useEffect, useState } from 'react';
import { useTrail, animated } from '@react-spring/web';
import Icon from './Icon';
import icons from '../config/iconExps';

interface ExpsProps {
  toggle: boolean;
}

const Exps = ({ toggle }: ExpsProps) => {
  const contactsAnim = useTrail(icons.length, {
    from: {
      opacity: 0,
      transform: 'translateX(-150px)',
      display: 'none' as const,
    },
    to: {
      opacity: toggle ? 1 : 0,
      transform: toggle ? 'translateX(0px)' : 'translateX(-150px)',
      display: 'block' as const,
    },
    config: { mass: 0.4, tension: 500, friction: 20 },
    delay: 200,
  });

  const [display, setDisplay] = useState(false);

  useEffect(() => {
    if (toggle && !display) {
      setDisplay(true);
    }
    if (!toggle && display) {
      setTimeout(() => {
        setDisplay(false);
      }, 1000);
    }
  }, [display, toggle]);

  return (
    <div className="relative left-[45px] top-[10px] flex h-[100px] w-[600px] flex-row flex-wrap items-center justify-start p-[5px] max-[750px]:left-0 max-[750px]:top-5 max-[750px]:h-[100px] max-[750px]:w-[280px] max-[750px]:flex-wrap max-[750px]:justify-start">
      {display &&
        contactsAnim.map((styles, index) => (
          <animated.div key={index} style={styles}>
            <Icon
              name={icons[index].name}
              title={icons[index].title}
              url={icons[index].url}
              background={false}
            />
          </animated.div>
        ))}
    </div>
  );
};

export default Exps;
